# Create tables
Base.metadata.create_all(bind=engine)

# Database dependency
@contextmanager
def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

# GraphQL Types
@strawberry.type
class ReviewType:
    id: int
    product_id: int
    author: str
    content: str
    rating: int
    created_at: datetime

@strawberry.type
class SellerType:
    id: int
    product_id: int
    name: str
    contact: str
    created_at: datetime

@strawberry.type
class CategoryType:
    id: int
    name: str

@strawberry.type
class ImageType:
    id: int
    product_id: int
    url: str
    alt_text: str

@strawberry.type
class ProductType:
    id: int
    name: str
    description: str
    price: float
    created_at: datetime
    reviews: List[ReviewType]
    sellers: List[SellerType]
    categories: List[CategoryType]
    images: List[ImageType]

# Resolvers
@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, id: int) -> Optional[ProductType]:
        with get_db() as db:
            product = db.query(Product).filter(Product.id == id).first()
            if product:
                return product
            return None
    
    @strawberry.field
    def products(self, info, skip: int = 0, limit: int = 100) -> List[ProductType]:
        with get_db() as db:
            return db.query(Product).offset(skip).limit(limit).all()

# Create GraphQL app
schema = strawberry.Schema(query=Query)
graphql_app = GraphQLRouter(schema)

# FastAPI app
app = FastAPI()
app.include_router(graphql_app, prefix="/graphql")

# Health check endpoint
